DELIMITER $$
--
-- Procedures
--
CREATE DEFINER=`root`@`localhost` PROCEDURE `refresh_leaderboard` ()   BEGIN
    -- Clear existing data
    TRUNCATE TABLE `leaderboard_data`;
    
    -- Insert fresh leaderboard data
        `student_id`, 
        `full_name`, 
        `username`, 
        `email`, 
        `avatar`, 
        `exams_taken`, 
        `total_score`, 
        `avg_percentage`, 
        `exams_passed`, 
        `total_correct`, 
        `total_wrong`, 
        `badges_count`, 
        `current_streak`
    )
    SELECT 
        u.id, 
        u.full_name, 
        u.username, 
        u.email, 
        u.avatar, 
        COUNT(DISTINCT ea.exam_id),
        COALESCE(SUM(ea.score), 0), 
        COALESCE(AVG(ea.percentage), 0), 
        COALESCE(SUM(CASE WHEN ea.passed = 1 THEN 1 ELSE 0 END), 0), 
        COALESCE(SUM(ea.correct_answers), 0), 
        COALESCE(SUM(ea.wrong_answers), 0), 
        COALESCE((SELECT COUNT(*) FROM student_achievements sa WHERE sa.student_id = u.id), 0), 
        COALESCE((SELECT current_streak FROM student_streaks ss WHERE ss.student_id = u.id), 0)
    FROM users u
    LEFT JOIN exam_attempts ea ON u.id = ea.student_id AND ea.status = 'completed'
    WHERE u.role = 'student'  -- Add your WHERE conditions here
    GROUP BY u.id, u.full_name, u.username, u.email, u.avatar;
END$$

