(3549, 'results', 'result,score,grade,performance', 'You can view your exam results in the \"Results\" section. Your scores are automatically calculated and displayed with detailed feedback.', 8, 1, '2026-04-20 23:55:44'),
(3550, 'certificate', 'certificate,completion,achievement', 'Certificates are automatically generated when you pass an exam with the required passing score. You can download them from the \"Certificates\" section.', 8, 1, '2026-04-20 23:55:44'),
(3551, 'registration', 'register,sign up,create account', 'To register as a student, click on the \"Register\" button on the homepage. Fill in your details and create a password to get started.', 8, 1, '2026-04-20 23:55:44'),
(3552, 'login', 'login,sign in,access', 'Use your email and password to login. If you forgot your password, click on \"Forgot Password\" to reset it.', 7, 1, '2026-04-20 23:55:44'),
(3553, 'forgot_password', 'forgot password,reset password,cant login', 'Click on \"Forgot Password\" on the login page, enter your email, and follow the instructions sent to your email to reset your password.', 7, 1, '2026-04-20 23:55:44'),
(3554, 'subjects', 'subject,course,topics', 'Our system covers various subjects including Mathematics, English, Science, and more. Check the exams page to see available subjects.', 6, 1, '2026-04-20 23:55:44'),
(3555, 'time_limit', 'time limit,duration,timer', 'Each exam has a specific time limit displayed before you start. The timer counts down while you take the exam.', 6, 1, '2026-04-20 23:55:44'),
(3556, 'questions', 'question,questions,type', 'Questions are multiple choice with four options. They are randomly ordered for each attempt to ensure fairness.', 6, 1, '2026-04-20 23:55:44'),
(3557, 'passing_score', 'passing score,pass mark,minimum score', 'Each exam has a passing score requirement (usually 50-70%). You need to achieve at least this percentage to pass.', 6, 1, '2026-04-20 23:55:44'),
(3558, 'retake', 'retake,retry,attempt again', 'You can retake exams if allowed by the administrator. Check the exam settings for retake availability.', 5, 1, '2026-04-20 23:55:44'),
(3559, 'help', 'help,support,assistance', 'For technical support, please contact missiontech.raph@gmail.com. For admin inquiries, email missiontech.admin@gmail.com', 9, 1, '2026-04-20 23:55:44'),
(3560, 'contact', 'contact,email,support', 'Student Support: missiontech.raph@gmail.com | Admin Support: missiontech.admin@gmail.com', 9, 1, '2026-04-20 23:55:44'),
