(3562, 'feature', 'feature,tools,functionality', 'Our system offers: Timed exams, instant results, certificates, study materials, leaderboard, and achievements!', 7, 1, '2026-04-20 23:55:44'),
(3563, 'thanks', 'thank you,thanks,appreciate', 'You\'re welcome! Feel free to ask if you need any more help. Good luck with your exams!', 8, 1, '2026-04-20 23:55:44'),
