INSERT INTO `exams` (`id`, `title`, `description`, `subject_id`, `duration_minutes`, `passing_score`, `total_questions`, `status`, `created_by`, `created_at`, `allow_retake`, `max_attempts`) VALUES
(1, 'Advanced Programming Concepts', 'Comprehensive exam covering object-oriented programming, algorithms, data structures, and software design patterns. Suitable for 2nd and 3rd year computer science students.', 34, 5, 70, 10, 'published', 1, '2026-03-24 15:18:59', 1, 0),
(2, 'Advanced Database Management', 'Comprehensive exam covering SQL queries, database design, normalization, transactions, and database administration. Designed for computer science and IT students.', 35, 5, 70, 10, 'published', 1, '2026-03-24 15:18:59', 1, 0),
(3, 'Full Stack Web Development', 'Comprehensive exam covering HTML5, CSS3, JavaScript, React, Node.js, and MongoDB. Ideal for web development students.', 36, 5, 70, 10, 'published', 1, '2026-03-24 15:18:59', 1, 0),
(4, 'Advanced Calculus and Linear Algebra', 'Advanced mathematics exam covering differential equations, integrals, matrices, vectors, and complex numbers. For engineering and mathematics students.', 37, 5, 70, 10, 'published', 1, '2026-03-24 15:18:59', 1, 0),
(5, 'Modern Physics', 'Comprehensive physics exam covering mechanics, thermodynamics, electromagnetism, quantum physics, and relativity. For science and engineering students.', 38, 5, 70, 10, 'published', 1, '2026-03-24 15:18:59', 1, 0),
(6, 'Business Management and Leadership', 'Comprehensive business exam covering management principles, organizational behavior, marketing, finance, and strategic management. For business students.', 39, 3, 70, 10, 'published', 1, '2026-03-24 15:19:00', 1, 0),
(7, 'English Literature and Composition', 'Comprehensive exam covering literary analysis, grammar, composition, famous authors, and literary devices. For literature and humanities students.', 40, 5, 70, 10, 'published', 1, '2026-03-24 15:19:00', 1, 0);
