INSERT INTO `questions` (`id`, `subject_id`, `topic_id`, `question_text`, `option_a`, `option_b`, `option_c`, `option_d`, `correct_option`, `difficulty`, `explanation`, `marks`, `status`, `created_by`, `created_at`) VALUES
(1, 34, NULL, 'What is the time complexity of binary search algorithm?', 'O(1)', 'O(log n)', 'O(n)', 'O(n²)', 'B', 'medium', 'Binary search divides the search space in half each time, resulting in logarithmic time complexity.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(2, 34, NULL, 'Which of the following is NOT an object-oriented programming principle?', 'Encapsulation', 'Inheritance', 'Polymorphism', 'Compilation', 'D', 'easy', 'Compilation is a process, not an OOP principle. The four main OOP principles are Encapsulation, Inheritance, Polymorphism, and Abstraction.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(3, 34, NULL, 'What is a closure in JavaScript?', 'A function that closes the browser', 'A function that has access to its outer scope even after the outer function has returned', 'A way to close database connections', 'A type of loop', 'B', 'hard', 'A closure is a function that remembers its lexical scope even when the function is executed outside that scope.', 2.00, 1, 1, '2026-03-24 15:18:59'),
(4, 34, NULL, 'Which data structure uses LIFO (Last In First Out) principle?', 'Queue', 'Stack', 'Array', 'Linked List', 'B', 'easy', 'Stack follows LIFO principle - the last element added is the first one removed.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(5, 34, NULL, 'What is the purpose of a constructor in object-oriented programming?', 'To destroy objects', 'To initialize objects', 'To create methods', 'To define variables', 'B', 'easy', 'Constructors are special methods used to initialize newly created objects.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(6, 34, NULL, 'What does SQL stand for?', 'Structured Query Language', 'Simple Query Language', 'Structured Question Language', 'System Query Language', 'A', 'easy', 'SQL stands for Structured Query Language, used for managing relational databases.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(7, 34, NULL, 'Which of the following is a NoSQL database?', 'MySQL', 'PostgreSQL', 'MongoDB', 'Oracle', 'C', 'medium', 'MongoDB is a NoSQL document database. MySQL, PostgreSQL, and Oracle are relational databases.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(8, 34, NULL, 'What is the primary purpose of version control systems like Git?', 'To compile code', 'To track changes in source code', 'To run tests', 'To deploy applications', 'B', 'easy', 'Version control systems track changes to files, allowing developers to collaborate and maintain history.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(9, 34, NULL, 'What does API stand for?', 'Application Programming Interface', 'Advanced Programming Integration', 'Application Protocol Interface', 'Automated Program Interface', 'A', 'easy', 'API stands for Application Programming Interface, allowing different software applications to communicate.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(10, 34, NULL, 'Which sorting algorithm has the best average-case time complexity?', 'Bubble Sort', 'Selection Sort', 'Insertion Sort', 'Quick Sort', 'D', 'hard', 'Quick Sort has average-case time complexity of O(n log n), better than O(n²) of bubble, selection, and insertion sort.', 2.00, 1, 1, '2026-03-24 15:18:59'),
(11, 35, NULL, 'What is the purpose of the SQL SELECT statement?', 'To insert data', 'To update data', 'To retrieve data', 'To delete data', 'C', 'easy', 'SELECT is used to retrieve data from database tables.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(12, 35, NULL, 'What does ACID stand for in database transactions?', 'Atomicity, Consistency, Isolation, Durability', 'Accuracy, Consistency, Integrity, Durability', 'Atomicity, Concurrency, Isolation, Data', 'All, Consistent, Isolated, Data', 'A', 'medium', 'ACID stands for Atomicity, Consistency, Isolation, and Durability - key properties of database transactions.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(13, 35, NULL, 'Which SQL statement is used to remove a table from the database?', 'REMOVE TABLE', 'DELETE TABLE', 'DROP TABLE', 'TRUNCATE TABLE', 'C', 'easy', 'DROP TABLE removes a table and its structure from the database.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(14, 35, NULL, 'What is a primary key?', 'A key used for encryption', 'A field that uniquely identifies each record in a table', 'A key that connects to another table', 'The first column in a table', 'B', 'easy', 'A primary key uniquely identifies each record in a database table.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(15, 35, NULL, 'What is database normalization?', 'Making the database faster', 'Organizing data to reduce redundancy and improve integrity', 'Encrypting the database', 'Backing up the database', 'B', 'medium', 'Normalization is the process of organizing data to minimize redundancy and dependency.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(16, 35, NULL, 'Which SQL join returns all records from both tables?', 'INNER JOIN', 'LEFT JOIN', 'RIGHT JOIN', 'FULL OUTER JOIN', 'D', 'hard', 'FULL OUTER JOIN returns all records when there is a match in either left or right table.', 2.00, 1, 1, '2026-03-24 15:18:59'),
(17, 35, NULL, 'What is a foreign key?', 'A key used for indexing', 'A field that references the primary key of another table', 'A unique identifier', 'A key for encryption', 'B', 'easy', 'A foreign key is a field that creates a link between two tables by referencing the primary key of another table.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(18, 35, NULL, 'What does SQL stand for?', 'Structured Query Language', 'Simple Query Language', 'Structured Question Language', 'System Query Language', 'A', 'easy', 'SQL stands for Structured Query Language, used for managing relational databases.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(19, 35, NULL, 'What is the difference between DELETE and TRUNCATE?', 'DELETE is faster than TRUNCATE', 'TRUNCATE removes all rows, DELETE can have WHERE clause', 'DELETE removes table structure', 'No difference', 'B', 'medium', 'TRUNCATE removes all rows without logging individual deletions. DELETE can use WHERE clause to delete specific rows.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(20, 35, NULL, 'What is a database index used for?', 'To speed up data retrieval', 'To encrypt data', 'To backup data', 'To compress data', 'A', 'easy', 'Indexes are used to improve the speed of data retrieval operations on database tables.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(21, 36, NULL, 'What does HTML stand for?', 'Hyper Text Markup Language', 'High Tech Modern Language', 'Hyper Transfer Markup Language', 'Home Tool Markup Language', 'A', 'easy', 'HTML stands for Hyper Text Markup Language, the standard markup language for web pages.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(22, 36, NULL, 'What is React?', 'A programming language', 'A JavaScript library for building user interfaces', 'A database', 'A CSS framework', 'B', 'easy', 'React is a JavaScript library for building user interfaces, developed by Facebook.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(23, 36, NULL, 'What does CSS stand for?', 'Creative Style Sheets', 'Cascading Style Sheets', 'Computer Style Sheets', 'Colorful Style Sheets', 'B', 'easy', 'CSS stands for Cascading Style Sheets, used for styling web pages.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(24, 36, NULL, 'What is Node.js?', 'A frontend framework', 'A JavaScript runtime built on Chrome\'s V8 engine', 'A database', 'A CSS preprocessor', 'B', 'medium', 'Node.js allows JavaScript to run on the server-side.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(25, 36, NULL, 'What is the purpose of the useState hook in React?', 'To manage state in functional components', 'To fetch data from API', 'To create routes', 'To style components', 'A', 'medium', 'useState is a React Hook that lets you add state to functional components.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(26, 36, NULL, 'What does REST stand for?', 'Representational State Transfer', 'Remote State Transfer', 'Restricted State Transfer', 'Real State Transfer', 'A', 'easy', 'REST stands for Representational State Transfer, an architectural style for web services.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(27, 36, NULL, 'What is MongoDB?', 'A SQL database', 'A NoSQL document database', 'A programming language', 'A web server', 'B', 'easy', 'MongoDB is a NoSQL document database that stores data in JSON-like documents.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(28, 36, NULL, 'What is the difference between let and var in JavaScript?', 'No difference', 'let has block scope, var has function scope', 'var is for constants', 'let cannot be reassigned', 'B', 'medium', 'let is block-scoped while var is function-scoped.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(29, 36, NULL, 'What is the purpose of the useEffect hook?', 'To handle side effects in React components', 'To create effects', 'To style components', 'To render components', 'A', 'medium', 'useEffect lets you perform side effects in functional components.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(30, 36, NULL, 'What does API stand for?', 'Application Programming Interface', 'Advanced Programming Integration', 'Application Protocol Interface', 'Automated Program Interface', 'A', 'easy', 'API stands for Application Programming Interface.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(31, 37, NULL, 'What is the derivative of x²?', 'x', '2x', 'x²', '2', 'B', 'easy', 'The derivative of x² is 2x using the power rule.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(32, 37, NULL, 'What is the integral of 2x?', 'x² + C', 'x²', '2x² + C', 'x + C', 'A', 'easy', 'The integral of 2x is x² + C, where C is the constant of integration.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(33, 37, NULL, 'What is the value of sin(π/2)?', '0', '1', '-1', 'Undefined', 'B', 'easy', 'sin(π/2) equals 1.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(34, 37, NULL, 'What is the derivative of e^x?', 'e^x', 'x e^(x-1)', 'ln(x)', '1', 'A', 'easy', 'The derivative of e^x is e^x itself.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(35, 37, NULL, 'What is the determinant of a 2x2 matrix [[a, b], [c, d]]?', 'ad + bc', 'ab - cd', 'ad - bc', 'ac - bd', 'C', 'medium', 'The determinant of a 2x2 matrix is ad - bc.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(36, 37, NULL, 'What is the limit of (sin x)/x as x approaches 0?', '0', '1', '∞', 'Undefined', 'B', 'hard', 'The limit of (sin x)/x as x approaches 0 equals 1.', 2.00, 1, 1, '2026-03-24 15:18:59'),
(37, 37, NULL, 'What is the value of log(1)?', '0', '1', '10', 'e', 'A', 'easy', 'log(1) equals 0 for any base.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(38, 37, NULL, 'What is the derivative of ln(x)?', '1/x', 'x', 'e^x', 'ln(x)', 'A', 'easy', 'The derivative of ln(x) is 1/x.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(39, 37, NULL, 'What is the sum of angles in a triangle?', '90°', '180°', '270°', '360°', 'B', 'easy', 'The sum of interior angles in a triangle is 180 degrees.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(40, 37, NULL, 'What is the Pythagorean theorem?', 'a² + b² = c²', 'a + b = c', 'a² - b² = c²', 'a × b = c²', 'A', 'easy', 'The Pythagorean theorem states that a² + b² = c² for right triangles.', 1.00, 1, 1, '2026-03-24 15:18:59'),
(41, 38, NULL, 'What is Newton\'s first law of motion?', 'Force equals mass times acceleration', 'An object at rest stays at rest unless acted upon by an external force', 'For every action there is an equal and opposite reaction', 'Momentum is conserved', 'B', 'easy', 'Newton\'s first law states that objects maintain their state of motion unless acted upon by a net force.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(42, 38, NULL, 'What is the formula for kinetic energy?', 'mgh', '½mv²', 'mc²', 'ma', 'B', 'easy', 'Kinetic energy = ½mv², where m is mass and v is velocity.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(43, 38, NULL, 'What is the speed of light in vacuum?', '3 × 10⁸ m/s', '3 × 10⁵ m/s', '3 × 10⁶ m/s', '3 × 10⁹ m/s', 'A', 'easy', 'The speed of light in vacuum is approximately 3 × 10⁸ meters per second.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(44, 38, NULL, 'What is the unit of force?', 'Joule', 'Newton', 'Watt', 'Pascal', 'B', 'easy', 'The SI unit of force is Newton (N).', 1.00, 1, 1, '2026-03-24 15:19:00'),
(45, 38, NULL, 'What is Ohm\'s law?', 'V = IR', 'P = IV', 'F = ma', 'E = mc²', 'A', 'easy', 'Ohm\'s law states that voltage equals current times resistance.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(46, 38, NULL, 'What is the formula for gravitational force?', 'F = G(m₁m₂)/r²', 'F = ma', 'F = mg', 'F = kq₁q₂/r²', 'A', 'medium', 'Newton\'s law of universal gravitation states F = G(m₁m₂)/r².', 1.00, 1, 1, '2026-03-24 15:19:00'),
(47, 38, NULL, 'What is the first law of thermodynamics?', 'Energy cannot be created or destroyed', 'Entropy always increases', 'Heat flows from hot to cold', 'PV = nRT', 'A', 'easy', 'The first law of thermodynamics is the conservation of energy.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(48, 38, NULL, 'What is the charge of an electron?', '1.6 × 10⁻¹⁹ C', '1.6 × 10⁻¹⁹ kg', '9.11 × 10⁻³¹ C', '1.6 × 10⁹ C', 'A', 'medium', 'The charge of an electron is -1.6 × 10⁻¹⁹ coulombs.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(49, 38, NULL, 'What is Einstein\'s mass-energy equivalence formula?', 'E = mc²', 'E = hf', 'F = ma', 'PV = nRT', 'A', 'easy', 'Einstein\'s famous equation E = mc² shows that mass and energy are equivalent.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(50, 38, NULL, 'What is the unit of power?', 'Joule', 'Watt', 'Newton', 'Pascal', 'B', 'easy', 'The SI unit of power is Watt (W).', 1.00, 1, 1, '2026-03-24 15:19:00'),
(51, 39, NULL, 'What is SWOT analysis?', 'Strengths, Weaknesses, Opportunities, Threats', 'Sales, Wages, Operations, Technology', 'Strategy, Workflow, Organization, Teams', 'Systems, Workflows, Objectives, Targets', 'A', 'easy', 'SWOT analysis examines Strengths, Weaknesses, Opportunities, and Threats.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(52, 39, NULL, 'What is the primary goal of marketing?', 'To increase sales', 'To create customer value and satisfaction', 'To reduce costs', 'To manage employees', 'B', 'medium', 'The main goal of marketing is to create and deliver value to customers.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(53, 39, NULL, 'What does SMART stand for in goal setting?', 'Specific, Measurable, Achievable, Relevant, Time-bound', 'Simple, Measurable, Attainable, Realistic, Timely', 'Strategic, Meaningful, Achievable, Relevant, Trackable', 'Specific, Manageable, Achievable, Realistic, Time-bound', 'A', 'easy', 'SMART goals are Specific, Measurable, Achievable, Relevant, and Time-bound.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(54, 39, NULL, 'What is the marketing mix (4Ps)?', 'Product, Price, Place, Promotion', 'People, Process, Physical evidence, Promotion', 'Product, Price, People, Promotion', 'Price, Place, People, Process', 'A', 'easy', 'The marketing mix consists of Product, Price, Place, and Promotion.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(55, 39, NULL, 'What is leadership?', 'The ability to influence others', 'The ability to manage resources', 'The ability to make money', 'The ability to hire employees', 'A', 'easy', 'Leadership is the ability to influence and guide individuals or teams.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(56, 39, NULL, 'What is the difference between management and leadership?', 'No difference', 'Management focuses on processes, leadership focuses on people', 'Leadership is about money', 'Management is about hiring', 'B', 'medium', 'Management focuses on systems and processes; leadership focuses on inspiring and motivating people.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(57, 39, NULL, 'What is corporate social responsibility (CSR)?', 'A business approach that contributes to sustainable development', 'A marketing strategy', 'A financial reporting requirement', 'A hiring policy', 'A', 'easy', 'CSR is a business model that helps companies be socially accountable to themselves, stakeholders, and the public.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(58, 39, NULL, 'What is a mission statement?', 'A statement of company goals', 'A statement of company purpose and values', 'A financial report', 'A marketing plan', 'B', 'easy', 'A mission statement defines an organization\'s purpose and primary objectives.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(59, 39, NULL, 'What is the purpose of a business plan?', 'To secure funding and guide operations', 'To hire employees', 'To market products', 'To manage finances', 'A', 'easy', 'A business plan outlines business goals and strategies for achieving them.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(60, 39, NULL, 'What is organizational culture?', 'The shared values and practices of an organization', 'The organizational structure', 'The company logo', 'The employee handbook', 'A', 'easy', 'Organizational culture encompasses the values, beliefs, and behaviors that determine how a company\'s employees interact.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(61, 40, NULL, 'Who wrote \"Romeo and Juliet\"?', 'Charles Dickens', 'William Shakespeare', 'Jane Austen', 'Mark Twain', 'B', 'easy', 'Romeo and Juliet was written by William Shakespeare.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(62, 40, NULL, 'What is a metaphor?', 'A comparison using \"like\" or \"as\"', 'A direct comparison between two unlike things', 'Exaggeration for effect', 'A sound word', 'B', 'easy', 'A metaphor directly compares two unlike things without using \"like\" or \"as\".', 1.00, 1, 1, '2026-03-24 15:19:00'),
(63, 40, NULL, 'What is the difference between a simile and a metaphor?', 'Simile uses \"like\" or \"as\", metaphor does not', 'No difference', 'Metaphor uses \"like\"', 'Simile is longer', 'A', 'easy', 'A simile uses \"like\" or \"as\" for comparison; a metaphor directly states the comparison.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(64, 40, NULL, 'What is alliteration?', 'Repetition of vowel sounds', 'Repetition of consonant sounds at the beginning of words', 'Exaggeration', 'A word that imitates sound', 'B', 'easy', 'Alliteration is the repetition of initial consonant sounds in neighboring words.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(65, 40, NULL, 'Who wrote \"Pride and Prejudice\"?', 'Emily Brontë', 'Jane Austen', 'Charlotte Brontë', 'Charles Dickens', 'B', 'easy', 'Pride and Prejudice was written by Jane Austen.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(66, 40, NULL, 'What is a sonnet?', 'A 14-line poem with a specific rhyme scheme', 'A 10-line poem', 'A type of novel', 'A play', 'A', 'medium', 'A sonnet is a 14-line poem with a specific rhyme scheme, often about love.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(67, 40, NULL, 'What is the theme of a story?', 'The main idea or underlying meaning', 'The plot', 'The characters', 'The setting', 'A', 'easy', 'Theme is the central idea or message in a work of literature.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(68, 40, NULL, 'What is onomatopoeia?', 'A word that imitates a sound', 'A type of metaphor', 'A comparison', 'Exaggeration', 'A', 'easy', 'Onomatopoeia is a word that phonetically imitates the sound it describes, like \"buzz\" or \"boom\".', 1.00, 1, 1, '2026-03-24 15:19:00'),
(69, 40, NULL, 'Who wrote \"To Kill a Mockingbird\"?', 'Harper Lee', 'Mark Twain', 'Ernest Hemingway', 'F. Scott Fitzgerald', 'A', 'easy', 'To Kill a Mockingbird was written by Harper Lee.', 1.00, 1, 1, '2026-03-24 15:19:00'),
(70, 40, NULL, 'What is the difference between fiction and non-fiction?', 'Fiction is invented, non-fiction is factual', 'No difference', 'Fiction is longer', 'Non-fiction is about science', 'A', 'easy', 'Fiction is imaginative storytelling; non-fiction is based on facts and reality.', 1.00, 1, 1, '2026-03-24 15:19:00');
